-- DUMMY DATA SCRIPT FOR HR MANAGEMENT PLATFORM
-- ===========================================

PRINT 'Inserting Departments...'
SET IDENTITY_INSERT kumarcapstone_Departments ON;
SET IDENTITY_INSERT kumarcapstone_Departments OFF;

PRINT 'Inserting Employees...'
SET IDENTITY_INSERT kumarcapstone_Employees ON;
SET IDENTITY_INSERT kumarcapstone_Employees OFF;

PRINT 'Inserting AspNetUsers...'
DECLARE @adminHash NVARCHAR(MAX) = (SELECT TOP 1 PasswordHash FROM kumarcapstone_AspNetUsers WHERE Email = 'admin@hrmanagement.com');
IF @adminHash IS NULL SET @adminHash = 'AQAAAAIAAYagAAAAEGv...'; -- fallback if empty


PRINT 'Inserting LeaveTypes and Balances...'
IF NOT EXISTS (SELECT 1 FROM kumarcapstone_LeaveTypes) BEGIN
  SET IDENTITY_INSERT kumarcapstone_LeaveTypes ON;
  SET IDENTITY_INSERT kumarcapstone_LeaveTypes OFF;
END

DECLARE @leaveType1 INT = (SELECT TOP 1 Id FROM kumarcapstone_LeaveTypes WHERE Name = 'Casual Leave');
IF @leaveType1 IS NULL SET @leaveType1 = 101;


PRINT 'Inserting Leave Requests...'
SET IDENTITY_INSERT kumarcapstone_LeaveRequests ON;
SET IDENTITY_INSERT kumarcapstone_LeaveRequests OFF;

PRINT 'Inserting Notifications...'
SET IDENTITY_INSERT kumarcapstone_Notifications ON;
SET IDENTITY_INSERT kumarcapstone_Notifications OFF;

PRINT 'Inserting Audit Logs...'
SET IDENTITY_INSERT kumarcapstone_AuditLogs ON;
SET IDENTITY_INSERT kumarcapstone_AuditLogs OFF;

PRINT 'Dummy data generation completed successfully!'